type PlayerSettings = {
    version: number,
    keybindings: Record<string, string>,   // path -> combo
    graphics: Record<string, string>,
}
export class SettingsManager {
    private static STORAGE_KEY = "tesserxel.settings"
    data: PlayerSettings;
    private load(): PlayerSettings {
        try {
            const raw = localStorage.getItem(SettingsManager.STORAGE_KEY);
            if (!raw) return this.default();
            const parsed = JSON.parse(raw);
            return this.migrate(parsed);
        } catch {
            return this.default();
        }
    }

    // ---------- save ----------

    save() {
        localStorage.setItem(
            SettingsManager.STORAGE_KEY,
            JSON.stringify(this.data)
        );
    }

    // ---------- default ----------

    private default(): PlayerSettings {
        return {
            version: 1,
            keybindings: {},
            graphics: {},
        }
    }

    private migrate(old: any): PlayerSettings {
        const currentVersion = 1;
        if (!old.version) old.version = 1;
        switch (old.version) {
            case 1:
                break;
        }
        old.version = currentVersion;
        return old as PlayerSettings;
    }
    clear() {
        localStorage.removeItem(SettingsManager.STORAGE_KEY)
        this.data = this.default()
    }
}